        return users.find(u => u.role === Role.MANAGER) || { fullName: 'مسؤول الشعبة' };
    }, [users]);

    // توليد وقت الطباعة الحالي
    const printTime = useMemo(() => new Date().toLocaleString('ar-EG', { 
        hour: '2-digit', 
        minute: '2-digit', 
        second: '2-digit',
        year: 'numeric',
        month: 'numeric',
        day: 'numeric'
    }), []);

