                                        <div className="hidden print:block text-center opacity-80">
                                            <div className="w-24 border-b border-black h-8 mb-1"></div>
                                            <p className="text-[9px] font-bold">الختم والتوقيع الرسمي</p>
                                        </div>
                                    </div>
                                )}
                            </div>
