            {toast && <Toast message={toast.message} onClose={() => { setToast(null); clearNotification(); }} onClick={() => setToast(null)} type={toast.type} />}

            {showSubmitConfirm && (
                <ConfirmModal 
                    title="تأكيد إرسال المهام" 
