                                        </div>
                                    )}

                                    <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                                        <button onClick={() => setActiveTab('new-report')} className="p-6 bg-white dark:bg-gray-800 rounded-3xl border dark:border-gray-700 shadow-sm flex flex-col items-center gap-3 transition-transform hover:scale-105 active:scale-95">
                                            <div className="w-12 h-12 bg-brand-light/10 text-brand-light rounded-2xl flex items-center justify-center">
                                                <PlusIcon className="w-6 h-6" />
                                            </div>
                                            <span className="font-bold dark:text-white">كتابة مهام اليوم</span>
                                        </button>
                                        <button onClick={() => setActiveTab('tasks')} className="p-6 bg-white dark:bg-gray-800 rounded-3xl border dark:border-gray-700 shadow-sm flex flex-col items-center gap-3 transition-transform hover:scale-105 active:scale-95 relative">
                                            <div className="w-12 h-12 bg-brand-accent-yellow/10 text-brand-accent-yellow rounded-2xl flex items-center justify-center">
                                                <InboxIcon className="w-6 h-6" />
                                            </div>
                                            <span className="font-bold dark:text-white">المهام الواردة</span>
                                            {unreadTasksCount > 0 && <span className="absolute top-4 right-4 w-6 h-6 bg-red-500 text-white text-xs font-bold rounded-full flex items-center justify-center border-2 border-white dark:border-gray-800 animate-pulse">{unreadTasksCount}</span>}
                                        </button>
                                    </div>
                                </div>
                            )}

                            {activeTab === 'new-report' && (
                                <form onSubmit={handleSubmitReportClick} className="bg-white dark:bg-gray-800 p-6 rounded-3xl shadow-sm border border-gray-100 dark:border-gray-700 space-y-6 animate-fade-in">
                                    <div className="flex items-center justify-between">
                                        <h3 className="text-xl font-bold dark:text-white">{editingDraftId ? 'تعديل المسودة' : 'جدول المهام اليومية'}</h3>
                                        <span className="text-[10px] text-gray-400 bg-gray-50 dark:bg-gray-700 px-3 py-1 rounded-full font-bold">بث مباشر للمدير</span>
                                    </div>

                                    <div className="space-y-4">
                                        <div className="flex items-center justify-between">
                                            <label className="text-sm font-bold text-gray-600 dark:text-gray-400">قائمة المهام:</label>
                                            <button type="button" onClick={() => setReportForm(p => ({...p, tasks: [...p.tasks, {id: Date.now().toString(), text: '', isDone: false}]}))} className="p-2 bg-brand-light/10 text-brand-light rounded-full hover:bg-brand-light/20 transition-all">
                                                <PlusIcon className="w-5 h-5" />
                                            </button>
                                        </div>

                                        <div className="space-y-3">
                                            {reportForm.tasks.map((task, index) => (
                                                <div key={task.id} className="flex gap-3 group animate-scale-in">
                                                    <button 
                                                        type="button" 
                                                        onClick={() => toggleTaskStatus(task.id)}
                                                        className={`w-6 h-6 mt-3 rounded-md border-2 transition-all flex items-center justify-center shrink-0 ${task.isDone ? 'bg-green-500 border-green-500' : 'border-gray-300 dark:border-gray-600'}`}
                                                    >
                                                        {task.isDone && <svg className="w-4 h-4 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" /></svg>}
                                                    </button>
                                                    <textarea 
                                                        value={task.text} 
                                                        onFocus={notifyTyping}
                                                        onChange={(e) => setReportForm(prev => ({ ...prev, tasks: prev.tasks.map(t => t.id === task.id ? { ...t, text: e.target.value } : t) }))} 
                                                        placeholder={`اكتب المهمة ${index + 1} هنا...`} 
                                                        rows={2}
                                                        className={`flex-1 px-4 py-3 border border-gray-100 dark:border-gray-700 rounded-2xl bg-gray-50 dark:bg-gray-700 dark:text-white outline-none focus:ring-2 focus:ring-brand-light/50 transition-all resize-none ${task.isDone ? 'opacity-50 line-through' : ''}`} 
                                                    />
                                                    {reportForm.tasks.length > 1 && (
                                                        <button type="button" onClick={() => setReportForm(p => ({...p, tasks: p.tasks.filter(t => t.id !== task.id)}))} className="p-3 text-red-500 hover:bg-red-50 dark:hover:bg-red-900/10 h-fit rounded-xl opacity-0 group-hover:opacity-100 transition-opacity">
                                                            <TrashIcon className="w-5 h-5" />
                                                        </button>
                                                    )}
                                                </div>
                                            ))}
                                        </div>
                                    </div>

                                    <div className="space-y-4 pt-4 border-t dark:border-gray-700">
                                        <textarea 
                                            placeholder="ما هي أبرز الإنجازات اليوم؟" 
                                            value={reportForm.accomplished} 
                                            onFocus={notifyTyping}
                                            onChange={e => setReportForm(p => ({...p, accomplished: e.target.value}))} 
                                            rows={3} 
                                            className="w-full px-4 py-3 border border-gray-100 dark:border-gray-700 rounded-2xl bg-gray-50 dark:bg-gray-700 dark:text-white outline-none focus:ring-2 focus:ring-brand-light/50" 
                                        />
                                        <textarea 
                                            placeholder="هل واجهتك أي معوقات؟" 
                                            value={reportForm.notAccomplished} 
                                            onFocus={notifyTyping}
                                            onChange={e => setReportForm(p => ({...p, notAccomplished: e.target.value}))} 
                                            rows={2} 
                                            className="w-full px-4 py-3 border border-gray-100 dark:border-gray-700 rounded-2xl bg-gray-50 dark:bg-gray-700 dark:text-white outline-none focus:ring-2 focus:ring-brand-light/50" 
                                        />
                                    </div>

                                    <div className="space-y-3">
                                        <div className="flex gap-3">
                                            <button type="button" onClick={() => fileInputRef.current?.click()} className="flex-1 flex items-center justify-center gap-2 p-3 bg-gray-50 dark:bg-gray-700 rounded-2xl border-2 border-dashed border-gray-200 dark:border-gray-600 text-gray-600 dark:text-gray-300">
                                                <DocumentTextIcon className="w-5 h-5" />
                                                <span className="text-xs font-bold">إرفاق ملف</span>
                                            </button>
                                            <button type="button" onClick={() => cameraInputRef.current?.click()} className="flex-1 flex items-center justify-center gap-2 p-3 bg-gray-50 dark:bg-gray-700 rounded-2xl border-2 border-dashed border-gray-200 dark:border-gray-600 text-gray-600 dark:text-gray-300">
                                                <CameraIcon className="w-5 h-5" />
                                                <span className="text-xs font-bold">كاميرا</span>
                                            </button>
                                        </div>
                                        <input type="file" ref={fileInputRef} className="hidden" multiple onChange={handleFileChange} />
                                        <input type="file" ref={cameraInputRef} className="hidden" accept="image/*" capture="environment" onChange={handleFileChange} />

                                        {reportForm.attachments.length > 0 && (
                                            <div className="grid grid-cols-2 gap-3 mt-4">
                                                {reportForm.attachments.map((file, idx) => (
                                                    <div key={idx} className="relative group p-2 bg-gray-50 dark:bg-gray-700 rounded-xl border dark:border-gray-600">
                                                        <button type="button" onClick={() => removeAttachment(idx)} className="absolute -top-2 -left-2 bg-red-500 text-white rounded-full p-1 shadow-lg z-10"><XMarkIcon className="w-4 h-4" /></button>
                                                        <div className="flex items-center gap-2 overflow-hidden">
                                                            {file.type.startsWith('image/') ? <img src={file.content} className="w-10 h-10 rounded-lg object-cover" /> : <div className="w-10 h-10 bg-brand-light/10 text-brand-light rounded-lg flex items-center justify-center"><PaperclipIcon className="w-5 h-5" /></div>}
                                                            <div className="flex-1 min-w-0"><p className="text-[10px] font-bold truncate dark:text-white">{file.name}</p></div>
                                                        </div>
                                                    </div>
                                                ))}
                                            </div>
                                        )}
                                    </div>

                                    <div className="flex gap-4 pt-4">
                                        <button type="button" onClick={handleSaveDraft} className="flex-1 py-4 bg-gray-100 dark:bg-gray-700 text-brand-dark dark:text-gray-200 rounded-2xl font-bold shadow-md active:scale-95 transition-all">حفظ مؤقت</button>
                                        <button type="submit" disabled={isSubmitting} className="flex-[2] py-4 bg-brand-light text-white rounded-2xl font-bold text-lg shadow-xl shadow-brand-light/30 transition-all active:scale-95 disabled:opacity-50">إرسال للمسؤول</button>
                                    </div>
                                </form>
                            )}

                            {activeTab === 'archive' && (
                                <div className="space-y-4 animate-fade-in">
                                    <h3 className="text-xl font-bold dark:text-white mb-4">الأرشيف المنجز</h3>
                                    {myReports.map(r => (
                                        <ReportView key={r.id} report={r} user={currentUser} viewerRole={Role.EMPLOYEE} onClick={() => openReportViewer(r)} />
                                    ))}
                                    {myReports.length === 0 && (
                                        <div className="text-center py-20 bg-white dark:bg-gray-800 rounded-3xl border border-dashed border-gray-200 dark:border-gray-700">
                                            <p className="text-gray-500">لا توجد تقارير منجزة حتى الآن.</p>
                                        </div>
                                    )}
                                </div>
                            )}

                            {activeTab === 'tasks' && <DirectTasksView />}

                            {activeTab === 'drafts' && (
                                 <div className="space-y-4 animate-fade-in">
                                 <h3 className="text-xl font-bold dark:text-white mb-4">المسودات الحالية ({myDrafts.length})</h3>
                                 {myDrafts.length > 0 ? myDrafts.map(draft => (
                                     <div key={draft.id} className="bg-white dark:bg-gray-800 p-4 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-700 flex items-center justify-between group">
                                         <div className="flex-1">
                                             <div className="flex items-center gap-2 mb-1">
                                                 <span className="text-[10px] font-bold text-brand-light bg-brand-light/10 px-2 py-0.5 rounded-full uppercase tracking-wider">مسودة</span>
                                                 <span className="text-xs text-gray-500">{draft.date}</span>
                                             </div>
                                             <p className="text-sm font-bold dark:text-white">{draft.tasks[0]?.text || 'بدون عنوان'}</p>
                                         </div>
                                         <div className="flex gap-2">
                                             <button onClick={() => handleEditDraft(draft)} className="p-2 text-brand-light hover:bg-brand-light/10 rounded-xl"><EditIcon className="w-5 h-5" /></button>
                                             <button onClick={() => deleteReport(draft.id)} className="p-2 text-red-500 hover:bg-red-50 rounded-xl"><TrashIcon className="w-5 h-5" /></button>
                                         </div>
                                     </div>
                                 )) : <div className="text-center py-20 bg-white dark:bg-gray-800 rounded-3xl border border-dashed border-gray-200 dark:border-gray-700"><p className="text-gray-500 font-bold">لا توجد مسودات محفوظة.</p></div>}
                             </div>
                            )}
                            {activeTab === 'profile' && <ProfileManagement user={currentUser} />}
                        </div>

                        <footer className="mt-12 py-8 border-t dark:border-gray-800 text-center space-y-2 no-print">
                            <p className="text-xs text-gray-400 font-medium tracking-wide">© نظام المهام اليومية الداخلي - 2025م</p>
                        </footer>
                    </div>
                </main>
            </div>

            {toast && <Toast message={toast.message} onClose={() => { setToast(null); clearNotification(); }} onClick={() => setToast(null)} type={toast.type} />}

            {showSubmitConfirm && (
                <ConfirmModal 
                    title="تأكيد إرسال المهام" 
                    message="هل أنت متأكد من اكتمال تقرير اليوم؟ سيتم إرساله للمدير فوراً." 
                    onConfirm={handleFinalSubmit} 
                    onCancel={() => setShowSubmitConfirm(false)} 
                    confirmText="تأكيد"
                    cancelText="تراجع"
                />
            )}

            {showLogoutConfirm && (
                <ConfirmModal 
                    title="تسجيل خروج" 
                    message="هل ترغب في مغادرة النظام الآن؟" 
                    onConfirm={logout} 
                    onCancel={() => setShowLogoutConfirm(false)} 
                    confirmText="خروج"
                    cancelText="بقاء"
                />
            )}
        </div>
    );
};

export default EmployeeDashboard;

import React, { useState, useMemo } from 'react';
import { useData } from '../context/DataContext';
import { Role, User, Report } from '../types';
import Avatar from './Avatar';
import EmployeeReportsView from './EmployeeReportsView';
import ReportDetail from './ReportDetail';
import ArrowRightIcon from './icons/ArrowRightIcon';
import DownloadIcon from './icons/DownloadIcon';
import UnitFolder from './UnitFolder';
import ArrowPathIcon from './icons/ArrowPathIcon';
import TrashIcon from './icons/TrashIcon';
import ConfirmModal from './ConfirmModal';

const ReportsView: React.FC = () => {
    const { users, reports, markReportAsViewed, deleteReport } = useData();
    const [searchTerm, setSearchTerm] = useState('');
    const [selectedEmployee, setSelectedEmployee] = useState<User | null>(null);
    const [viewingReport, setViewingReport] = useState<Report | null>(null);
    const [dateFrom, setDateFrom] = useState('');
    const [dateTo, setDateTo] = useState('');
    const [showOnlyUnread, setShowOnlyUnread] = useState(false);
    const [showDeleteConfirm, setShowDeleteConfirm] = useState(false);

    const employees = useMemo(() => users.filter(u => u.role === Role.EMPLOYEE), [users]);

    const getUnreadCount = (employeeId: string): number => {
        return reports.filter(r => r.userId === employeeId && !r.isViewedByManager && r.status === 'submitted').length;
    };

    const filteredEmployees = useMemo(() => {
        let employeesToShow = employees;
        if (searchTerm) {
            employeesToShow = employeesToShow.filter(employee =>
                employee.fullName.toLowerCase().includes(searchTerm.toLowerCase())
            );
        }
        if (showOnlyUnread) {
            employeesToShow = employeesToShow.filter(employee => getUnreadCount(employee.id) > 0);
        }
        if (dateFrom || dateTo) {
            const from = dateFrom || '0000-01-01';
            const to = dateTo || '9999-12-31';
            const employeesWithReportsInRange = new Set(
                reports
                    .filter(report => report.date >= from && report.date <= to)
                    .map(report => report.userId)
            );
            employeesToShow = employeesToShow.filter(employee => employeesWithReportsInRange.has(employee.id));
        }
        return employeesToShow;
    }, [employees, reports, searchTerm, showOnlyUnread, dateFrom, dateTo]);

    const unitOrder = ['وحدة التمكين الفني', 'وحدة التنسيق الفني'];

    const groupedEmployees = useMemo(() => {
        const groups: { [key: string]: User[] } = {
            'وحدة التمكين الفني': [],
            'وحدة التنسيق الفني': [],
        };
        filteredEmployees.forEach(employee => {
            if (employee.unit && (employee.unit === 'وحدة التمكين الفني' || employee.unit === 'وحدة التنسيق الفني')) {
                groups[employee.unit].push(employee);
            }
        });
        return groups;
    }, [filteredEmployees]);


    const handleViewReport = (report: Report) => {
        if (!report.isViewedByManager) {
            markReportAsViewed(report.id);
        }
        // العرض فوري لأن البيانات محملة بالكامل مع التطبيق
        setViewingReport(report);
    };

    const handleResetFilters = () => {
        setSearchTerm('');
        setDateFrom('');
        setDateTo('');
        setShowOnlyUnread(false);
    };

    const handleDeleteReport = async () => {
        if (viewingReport) {
            await deleteReport(viewingReport.id);
            setShowDeleteConfirm(false);
            setViewingReport(null);
        }
    };

    if (viewingReport && selectedEmployee) {
        return (
            <div className="bg-white dark:bg-gray-800 rounded-3xl shadow-xl overflow-hidden animate-fade-in border dark:border-gray-700 min-h-full flex flex-col">
                <div className="flex flex-col md:flex-row items-center justify-between p-4 bg-gray-50 dark:bg-gray-900/50 border-b dark:border-gray-700 gap-4 no-print sticky top-0 z-50">
                     <button 
                        onClick={() => setViewingReport(null)}
                        className="flex items-center gap-2 px-4 py-2 bg-white dark:bg-gray-700 text-brand-dark dark:text-gray-100 rounded-xl shadow-sm border dark:border-gray-600 hover:bg-gray-50 transition-all font-bold active:scale-95"
                    >
                        <ArrowRightIcon className="w-5 h-5" />
                        <span>العودة للمنتسب</span>
                    </button>

                     <div className="flex items-center gap-4">
                         <Avatar src={selectedEmployee.profilePictureUrl} name={selectedEmployee.fullName} size={40} />
                         <div>
                            <h3 className="text-xs md:text-sm font-bold text-brand-dark dark:text-gray-100 leading-tight">التقرير #{viewingReport.sequenceNumber}: {selectedEmployee.fullName}</h3>
                            <p className="text-[10px] text-gray-500">{viewingReport.date} - {viewingReport.day}</p>
                         </div>
                    </div>

                    <div className="flex items-center gap-2">
                        <button onClick={() => setShowDeleteConfirm(true)} className="p-2 text-red-500 hover:bg-red-50 dark:hover:bg-red-900/20 rounded-lg transition-all" title="حذف التقرير">
                            <TrashIcon className="w-5 h-5" />
                        </button>
                        <button onClick={() => window.print()} className="flex items-center gap-2 px-4 py-2 bg-brand-light text-white rounded-lg font-bold shadow-md text-xs hover:bg-brand-dark transition-all">
                            <DownloadIcon className="w-4 h-4" />
                            <span>طباعة / PDF</span>
                        </button>
                    </div>
                </div>

                <div id="printable-area" className="flex-1 overflow-y-auto no-scrollbar bg-white dark:bg-gray-900">
                    <ReportDetail report={viewingReport} user={selectedEmployee} viewerRole={Role.MANAGER} />
                </div>

                {showDeleteConfirm && (
                    <ConfirmModal
                        title="تأكيد حذف التقرير"
                        message="سيتم حذف التقرير نهائياً من سجلات المنتسب. هل أنت متأكد؟"
                        onConfirm={handleDeleteReport}
                        onCancel={() => setShowDeleteConfirm(false)}
                        confirmText="تأكيد الحذف"
                        confirmButtonClass="bg-red-600"
                    />
                )}
            </div>
        );
    }

    if (selectedEmployee) {
        return (
            <EmployeeReportsView 
                employee={selectedEmployee} 
                onViewReport={handleViewReport} 
                onBack={() => setSelectedEmployee(null)} 
            />
        );
    }

    const hasFilteredResults = Object.keys(groupedEmployees).some(key => groupedEmployees[key].length > 0);

    return (
        <div className="space-y-6 animate-fade-in">
            <div className="p-5 bg-white dark:bg-gray-800 rounded-2xl shadow-sm border dark:border-gray-700 space-y-4">
                <div className="flex flex-col md:flex-row gap-4 items-end">
                    <div className="flex-1 w-full">
                        <label className="block text-xs font-bold text-gray-500 mb-1">البحث عن منتسب</label>
                        <input
                            type="text"
                            placeholder="اكتب اسم المنتسب هنا..."
                            value={searchTerm}
                            onChange={(e) => setSearchTerm(e.target.value)}
                            className="w-full px-4 py-2 text-sm border dark:border-gray-600 rounded-xl bg-gray-50 dark:bg-gray-700 dark:text-gray-200 focus:ring-2 focus:ring-brand-light outline-none"
                        />
                    </div>
                    <div className="flex items-center gap-2">
                        <div className="flex items-center h-10 px-4 bg-gray-100 dark:bg-gray-700 rounded-xl">
                            <input id="unread-only" type="checkbox" checked={showOnlyUnread} onChange={e => setShowOnlyUnread(e.target.checked)} className="h-4 w-4 rounded border-gray-300 text-brand-light" />
                            <label htmlFor="unread-only" className="mr-2 text-xs font-bold text-gray-600 dark:text-gray-300 cursor-pointer">غير مقروءة</label>
                        </div>
                        <button onClick={handleResetFilters} className="h-10 px-4 bg-gray-100 dark:bg-gray-600 rounded-xl text-xs font-bold text-gray-500 flex items-center gap-2 hover:bg-gray-200">
                            <ArrowPathIcon className="w-4 h-4" /> إعادة تعيين
                        </button>
                    </div>
                </div>

                <div className="grid grid-cols-2 md:grid-cols-2 gap-4 pt-4 border-t dark:border-gray-700">
                    <div>
                        <label className="block text-[10px] font-bold text-gray-400 mb-1 uppercase">من تاريخ</label>
                        <input type="date" value={dateFrom} onChange={e => setDateFrom(e.target.value)} className="w-full px-3 py-2 text-xs border dark:border-gray-600 rounded-lg bg-white dark:bg-gray-700 dark:text-white" />
                    </div>
                    <div>
                        <label className="block text-[10px] font-bold text-gray-400 mb-1 uppercase">إلى تاريخ</label>
                        <input type="date" value={dateTo} onChange={e => setDateTo(e.target.value)} min={dateFrom} className="w-full px-3 py-2 text-xs border dark:border-gray-600 rounded-lg bg-white dark:bg-gray-700 dark:text-white" />
                    </div>
                </div>
            </div>

            {hasFilteredResults ? (
                <div className="space-y-6">
                    {unitOrder.map(unitName => {
                        const employeesInUnit = groupedEmployees[unitName];
                        if (!employeesInUnit || employeesInUnit.length === 0) return null;
                        return (
                            <UnitFolder 
                                key={unitName} 
                                unitName={unitName} 
                                employees={employeesInUnit} 
                                getUnreadCount={getUnreadCount} 
                                onEmployeeClick={(emp) => setSelectedEmployee(emp)} 
                            />
                        );
                    })}
                </div>
            ) : (
                <div className="text-center py-20 bg-white dark:bg-gray-800 rounded-2xl border border-dashed border-gray-200 dark:border-gray-700">
                    <p className="text-gray-400 text-sm">لا توجد نتائج مطابقة للبحث حالياً.</p>
                </div>
            )}
        </div>
    );
};

export default ReportsView;

import React, { useEffect, useState } from 'react';
import { Report, User, Role } from '../types';
import { useData } from '../context/DataContext';
import ReportDetail from './ReportDetail';
import XCircleIcon from './icons/XCircleIcon';
import Avatar from './Avatar';
import DownloadIcon from './icons/DownloadIcon';
import TrashIcon from './icons/TrashIcon';
import ConfirmModal from './ConfirmModal';

interface ReportDetailModalProps {
    report: Report;
    user: User;
    viewerRole: Role;
    onClose: () => void;
    hideMargin?: boolean;
}

const ReportDetailModal: React.FC<ReportDetailModalProps> = ({ report, user, viewerRole, onClose, hideMargin = false }) => {
    const { markReportAsViewed, markCommentAsRead, deleteReport } = useData();
    const [showDeleteConfirm, setShowDeleteConfirm] = useState(false);

    useEffect(() => {
        // تحديث حالة القراءة
        if (viewerRole === Role.MANAGER && !report.isViewedByManager) {
            markReportAsViewed(report.id);
        }
        if (viewerRole === Role.EMPLOYEE && report.managerComment && !report.isCommentReadByEmployee) {
            markCommentAsRead(report.id);
        }
    }, [report.id, viewerRole, markReportAsViewed, markCommentAsRead]);

    const handleDelete = async () => {
        await deleteReport(report.id);
        setShowDeleteConfirm(false);
        onClose();
    };

    return (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/70 backdrop-blur-sm p-0 sm:p-4 md:p-8" aria-modal="true" role="dialog" onClick={onClose}>
            <div id="printable-area" className="relative w-full h-full max-w-5xl sm:h-[95vh] sm:rounded-[2.5rem] bg-white dark:bg-gray-800 shadow-2xl flex flex-col overflow-hidden" onClick={e => e.stopPropagation()}>

                {/* رأس الشاشة الرقمي */}
                <div className="p-4 sm:p-6 border-b dark:border-gray-700 no-print flex items-center justify-between bg-gray-50 dark:bg-gray-900/50">
                    <div className="flex items-center space-x-3 space-x-reverse">
                         <Avatar src={user.profilePictureUrl} name={user.fullName} size={48} />
                         <div>
                            <h3 className="text-base md:text-lg font-bold text-brand-dark dark:text-gray-100 leading-tight">{user.fullName}</h3>
                            <p className="text-[10px] md:text-xs text-gray-500 dark:text-gray-400">تقرير {report.date} - #{report.sequenceNumber}</p>
                         </div>
