import { User, Report, Announcement, DirectTask, Role } from '../types';
import { supabase, isSupabaseConfigured } from './supabaseConfig';

interface AppState {
    users: User[];
    reports: Report[];
    announcements: Announcement[];
    directTasks: DirectTask[];
    isCloud: boolean;
}

const CACHE_KEY = 'daily_tasks_data_cache';
const generateId = () => crypto.randomUUID();

export const mapUser = (row: any): User => ({
    id: row.id,
    fullName: row.full_name,
    badgeNumber: row.badge_number,
    username: row.username,
    password: row.password,
    role: row.role as Role,
    jobTitle: row.job_title,
    unit: row.unit,
    profilePictureUrl: row.profile_picture_url
});

export const mapReport = (row: any): Report => ({
    id: row.id,
    userId: row.user_id,
    sequenceNumber: row.sequence_number,
    date: row.date,
    day: row.day,
    tasks: row.tasks || [],
    accomplished: row.accomplished,
    notAccomplished: row.not_accomplished,
    attachments: row.attachments || [],
    managerComment: row.manager_comment,
    isViewedByManager: row.is_viewed_by_manager,
    isCommentReadByEmployee: row.is_comment_read_by_employee,
    rating: row.rating,
    status: row.status
});

export const mapAnnouncement = (row: any): Announcement => ({
    id: row.id,
    content: row.content,
    date: row.date,
    readBy: row.read_by || []
});

export const mapDirectTask = (row: any): DirectTask => ({
    id: row.id,
    managerId: row.manager_id,
    employeeId: row.employee_id,
    content: row.content,
    sentAt: row.sent_at,
    status: row.status,
    acknowledgedAt: row.acknowledged_at,
    rejectionReason: row.rejection_reason,
    isReadByEmployee: row.is_read_by_employee
});

/**
 * جلب البيانات مع دعم التخزين المحلي لضمان السرعة ومعالجة أخطاء محسنة
 */
export const fetchInitialData = async (): Promise<AppState> => {
    const cachedData = localStorage.getItem(CACHE_KEY);
    const hasCache = !!cachedData;

    if (!isSupabaseConfigured()) {
        if (hasCache) return JSON.parse(cachedData!);
        throw new Error("تكوين قاعدة البيانات غير مكتمل.");
    }

    try {
        const [usersRes, reportsRes, annRes, tasksRes] = await Promise.all([
            supabase.from('users').select('*'),
            supabase.from('reports').select('*').order('date', { ascending: false }),
            supabase.from('announcements').select('*'),
            supabase.from('direct_tasks').select('*')
        ]);

        // التحقق من وجود أخطاء في أي من الاستعلامات
        const errors = [usersRes.error, reportsRes.error, annRes.error, tasksRes.error].filter(Boolean);
        if (errors.length > 0) {
            const errorMsg = errors[0]?.message || "خطأ في جلب البيانات من الخادم.";
            throw new Error(errorMsg);
        }

        const freshData: AppState = {
            users: (usersRes.data || []).map(mapUser),
            reports: (reportsRes.data || []).map(mapReport),
            announcements: (annRes.data || []).map(mapAnnouncement),
            directTasks: (tasksRes.data || []).map(mapDirectTask),
            isCloud: true
        };

        // تحديث الكاش المحلي
        localStorage.setItem(CACHE_KEY, JSON.stringify(freshData));
        return freshData;
    } catch (error: any) {
        console.warn("API Service: فشل الاتصال، محاولة استخدام الكاش:", error);
        if (hasCache) {
            return JSON.parse(cachedData!);
        }
        // التأكد من إرجاع خطأ نصي
        throw new Error(error.message || "حدث خطأ غير متوقع أثناء الاتصال بقاعدة البيانات.");
    }
};

export const subscribeToAllChanges = (onUpdate: (payload: any) => void) => {
    if (!isSupabaseConfigured()) return () => {};

    try {
        const channel = supabase
            .channel('schema-db-changes')
            .on('postgres_changes', { event: '*', schema: 'public', table: 'reports' }, (p) => onUpdate({ table: 'reports', ...p }))
            .on('postgres_changes', { event: '*', schema: 'public', table: 'direct_tasks' }, (p) => onUpdate({ table: 'direct_tasks', ...p }))
            .on('postgres_changes', { event: '*', schema: 'public', table: 'announcements' }, (p) => onUpdate({ table: 'announcements', ...p }))
            .on('postgres_changes', { event: '*', schema: 'public', table: 'users' }, (p) => onUpdate({ table: 'users', ...p }))
            .subscribe();

        return () => { supabase.removeChannel(channel); };
    } catch (e) {
        console.error("Realtime subscription failed", e);
        return () => {};
    }
};

export const createReport = async (report: Omit<Report, 'id' | 'sequenceNumber' | 'status'>): Promise<Report> => {
    const { data: maxSeqData } = await supabase
        .from('reports')
        .select('sequence_number')
        .eq('user_id', report.userId)
        .eq('status', 'submitted')
        .order('sequence_number', { ascending: false })
        .limit(1);

    const maxSeq = maxSeqData && maxSeqData.length > 0 ? maxSeqData[0].sequence_number : 0;
    const newId = generateId();
    const dbReport = {
        id: newId, 
        user_id: report.userId, 
        sequence_number: maxSeq + 1, 
        date: report.date, 
        day: report.day,
        tasks: report.tasks, 
        accomplished: report.accomplished, 
        not_accomplished: report.notAccomplished,
        attachments: report.attachments, 
        status: 'submitted', 
        is_viewed_by_manager: false, 
        is_comment_read_by_employee: false
    };
    const { error } = await supabase.from('reports').insert(dbReport);
    if (error) throw error;
    return { ...report, id: newId, status: 'submitted', sequenceNumber: maxSeq + 1 } as Report;
};

export const saveOrUpdateDraft = async (draft: Partial<Report>): Promise<Report> => {
    const dbPayload = {
        user_id: draft.userId, date: draft.date, day: draft.day, tasks: draft.tasks || [],
        accomplished: draft.accomplished || '', not_accomplished: draft.notAccomplished || '',
        attachments: draft.attachments || [], status: 'draft', sequence_number: null
    };

    if (draft.id && !draft.id.startsWith('temp-')) {
        const { error } = await supabase.from('reports').update(dbPayload).eq('id', draft.id);
        if (error) throw error;
        return { ...draft, status: 'draft' } as Report;
    } else {
        const newId = generateId();
        const { error } = await supabase.from('reports').insert({ id: newId, ...dbPayload });
        if (error) throw error;
        return { ...draft, id: newId, status: 'draft' } as Report;
    }
};

export const updateReport = async (updatedReport: Report): Promise<Report> => {
    const { error } = await supabase.from('reports').update({
        tasks: updatedReport.tasks, accomplished: updatedReport.accomplished,
        not_accomplished: updatedReport.notAccomplished, attachments: updatedReport.attachments,
        manager_comment: updatedReport.managerComment, rating: updatedReport.rating,
        status: updatedReport.status, is_viewed_by_manager: updatedReport.isViewedByManager,
        is_comment_read_by_employee: updatedReport.isCommentReadByEmployee
    }).eq('id', updatedReport.id);
    if (error) throw error;
    return updatedReport;
};

export const deleteReport = async (reportId: string): Promise<void> => {
    await supabase.from('reports').delete().eq('id', reportId);
};

export const markReportAsViewed = async (reportId: string): Promise<void> => {
    await supabase.from('reports').update({ is_viewed_by_manager: true }).eq('id', reportId);
};

export const markAllReportsAsReadForUser = async (userId: string): Promise<void> => {
    await supabase.from('reports').update({ is_viewed_by_manager: true }).eq('user_id', userId).eq('status', 'submitted');
};

export const markCommentAsRead = async (reportId: string): Promise<void> => {
    await supabase.from('reports').update({ is_comment_read_by_employee: true }).eq('id', reportId);
};

export const createDirectTask = async (task: Omit<DirectTask, 'id' | 'sentAt' | 'status' | 'isReadByEmployee'>): Promise<DirectTask> => {
    const newId = generateId();
    const dbTask = { id: newId, manager_id: task.managerId, employee_id: task.employeeId, content: task.content, sent_at: new Date().toISOString(), status: 'pending', is_read_by_employee: false };
    const { error } = await supabase.from('direct_tasks').insert(dbTask);
    if (error) throw error;
    return { ...task, id: newId, sentAt: dbTask.sent_at, status: 'pending', isReadByEmployee: false };
};

export const updateDirectTaskStatus = async (taskId: string, status: 'acknowledged' | 'rejected', rejectionReason?: string): Promise<void> => {
    const updates: any = { status };
    if (rejectionReason) updates.rejection_reason = rejectionReason;
    if (status === 'acknowledged') updates.acknowledged_at = new Date().toISOString();
    await supabase.from('direct_tasks').update(updates).eq('id', taskId);
};

export const markDirectTaskAsRead = async (taskId: string): Promise<void> => {
    await supabase.from('direct_tasks').update({ is_read_by_employee: true }).eq('id', taskId);
};

export const createUser = async (user: Omit<User, 'id'>): Promise<User> => {
    const newId = generateId();
    await supabase.from('users').insert({ id: newId, full_name: user.fullName, badge_number: user.badgeNumber, username: user.username, password: user.password, role: user.role, job_title: user.jobTitle, unit: user.unit, profile_picture_url: user.profilePictureUrl });
    return { ...user, id: newId };
};

export const updateUser = async (updatedUser: User): Promise<User> => {
    await supabase.from('users').update({ full_name: updatedUser.fullName, badge_number: updatedUser.badgeNumber, username: updatedUser.username, password: updatedUser.password, role: updatedUser.role, job_title: updatedUser.jobTitle, unit: updatedUser.unit, profile_picture_url: updatedUser.profilePictureUrl }).eq('id', updatedUser.id);
    return updatedUser;
};

export const deleteUser = async (userId: string): Promise<void> => {
    await supabase.from('reports').delete().eq('user_id', userId);
    await supabase.from('users').delete().eq('id', userId);
};

export const createAnnouncement = async (content: string): Promise<Announcement> => {
    const newId = generateId();
    const { error } = await supabase.from('announcements').insert({ id: newId, content, date: new Date().toISOString(), read_by: [] });
    if (error) throw error;
    return { id: newId, content, date: new Date().toISOString(), readBy: [] };
};

export const updateAnnouncement = async (announcementId: string, content: string): Promise<Announcement> => {
    await supabase.from('announcements').update({ content }).eq('id', announcementId);
    return { id: announcementId, content } as Announcement;
};

export const deleteAnnouncement = async (announcementId: string): Promise<void> => {
    await supabase.from('announcements').delete().eq('id', announcementId);
};

export const markAnnouncementAsRead = async (announcementId: string, userId: string): Promise<void> => {
    const { data } = await supabase.from('announcements').select('read_by').eq('id', announcementId).single();
    if (data) {
        const currentReadBy = data.read_by || [];
        if (!currentReadBy.some((r: any) => r.userId === userId)) {
            const updatedReadBy = [...currentReadBy, { userId, readAt: new Date().toISOString() }];
            await supabase.from('announcements').update({ read_by: updatedReadBy }).eq('id', announcementId);
        }
    }
};

import React, { createContext, useState, useContext, ReactNode, useMemo, useCallback, useEffect, useRef } from 'react';
import { User, Report, Announcement, DirectTask } from '../types';
import * as api from '../services/apiService';

interface AppState {
    users: User[];
    reports: Report[];
    announcements: Announcement[];
    directTasks: DirectTask[];
}

interface DataContextType extends AppState {
    isDataLoading: boolean;
    isCloud: boolean;
    error: string | null;
    isSyncing: boolean;
    refreshData: () => Promise<void>;
    notification: { message: string, type: 'info' | 'success', id: number } | null;
    clearNotification: () => void;
    getUserById: (id: string) => User | undefined;
    addReport: (report: Omit<Report, 'id' | 'sequenceNumber' | 'status'>) => Promise<void>;
    updateReport: (updatedReport: Report) => Promise<void>;
    saveOrUpdateDraft: (draft: Partial<Report>) => Promise<void>;
    deleteReport: (reportId: string) => Promise<void>;
    markReportAsViewed: (reportId: string) => Promise<void>;
    markAllReportsAsReadForUser: (userId: string) => Promise<void>;
    markCommentAsRead: (reportId: string) => Promise<void>;
    addUser: (user: Omit<User, 'id'>) => Promise<void>;
    updateUser: (user: User) => Promise<void>;
    deleteUser: (userId: string) => Promise<void>;
    addAnnouncement: (content: string) => Promise<void>;
    updateAnnouncement: (announcementId: string, content: string) => Promise<void>;
    deleteAnnouncement: (announcementId: string) => Promise<void>;
    markAnnouncementAsRead: (announcementId: string, userId: string) => Promise<void>;
    addDirectTask: (task: Omit<DirectTask, 'id' | 'sentAt' | 'status' | 'isReadByEmployee'>) => Promise<void>;
    updateDirectTaskStatus: (taskId: string, status: 'acknowledged' | 'rejected', rejectionReason?: string) => Promise<void>;
    markDirectTaskAsRead: (taskId: string) => Promise<void>;
    unlockAudio: () => void;
    testNotification: () => void;
}

const DataContext = createContext<DataContextType | undefined>(undefined);

export const DataProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
    const [appState, setAppState] = useState<AppState>(() => {
        try {
            const cached = localStorage.getItem('daily_tasks_data_cache');
            return cached ? JSON.parse(cached) : { users: [], reports: [], announcements: [], directTasks: [] };
        } catch (e) {
            return { users: [], reports: [], announcements: [], directTasks: [] };
        }
    });

    const [isDataLoading, setIsDataLoading] = useState(false);
    const [isSyncing, setIsSyncing] = useState(false);
    const [isCloud, setIsCloud] = useState(false);
    const [error, setError] = useState<string | null>(null);
    const [notification, setNotification] = useState<{ message: string, type: 'info' | 'success', id: number } | null>(null);

    const audioRef = useRef<HTMLAudioElement | null>(null);

    useEffect(() => {
        audioRef.current = new Audio('https://assets.mixkit.co/active_storage/sfx/2358/2358-preview.mp3');
        audioRef.current.load();
    }, []);

    const unlockAudio = useCallback(() => {
        if (audioRef.current) {
            audioRef.current.play().then(() => {
                audioRef.current?.pause();
                if (audioRef.current) audioRef.current.currentTime = 0;
            }).catch(() => {});
        }
    }, []);

    const playNotificationSound = useCallback(() => {
        if (audioRef.current) {
            audioRef.current.currentTime = 0;
            audioRef.current.volume = 0.6;
            audioRef.current.play().catch(() => {});
        }
    }, []);

    const triggerNotification = useCallback((title: string, body: string, type: 'info' | 'success' = 'info') => {
        setNotification({ message: body, type, id: Date.now() });
        playNotificationSound();

        if ("vibrate" in navigator) {
            navigator.vibrate([100, 50, 100]);
        }

        if ("Notification" in window && Notification.permission === "granted") {
            const options: any = {
                body,
                icon: 'https://img.icons8.com/fluency/192/task.png',
                vibrate: [200, 100, 200],
            };
            navigator.serviceWorker.ready.then(reg => reg.showNotification(title, options));
        }
    }, [playNotificationSound]);

    const testNotification = useCallback(() => {
        triggerNotification("تجربة النظام", "أهلاً بك، نظام التنبيهات يعمل بنجاح.", "success");
    }, [triggerNotification]);

    const clearNotification = useCallback(() => setNotification(null), []);

    const loadData = useCallback(async (silent = false) => {
        const hasLocalData = appState.users.length > 0;
        if (!hasLocalData && !silent) setIsDataLoading(true);
        else if (hasLocalData) setIsSyncing(true);

        try {
            const data = await api.fetchInitialData();
            setAppState({
                users: data.users,
                reports: data.reports,
                announcements: data.announcements,
                directTasks: data.directTasks
            });
            setIsCloud(data.isCloud);
            setError(null);
        } catch (err: any) {
            const finalMessage = typeof err === 'string' ? err : (err.message || "خطأ في الاتصال بالخادم.");
            console.error("Data loading error:", finalMessage);

            // لا نعرض شاشة الخطأ الكبيرة إذا كان لدينا كاش محلي
            if (appState.users.length === 0) {
                setError(finalMessage);
            }
        } finally {
            setIsDataLoading(false);
            setIsSyncing(false);
        }
    }, [appState.users.length]);

    const refreshData = useCallback(async () => {
        await loadData(true);
    }, [loadData]);

    useEffect(() => {
        loadData();
        const unsubscribe = api.subscribeToAllChanges((payload) => {
            const { table, eventType, new: newRecord } = payload;
            setAppState(prev => {
                const newState = { ...prev };
                const loggedInUserId = localStorage.getItem('loggedInUserId') || sessionStorage.getItem('loggedInUserId');
                const currentUser = prev.users.find(u => u.id === loggedInUserId);

                if (table === 'reports') {
                    if (eventType === 'INSERT' || eventType === 'UPDATE') {
                        const mapped = api.mapReport(newRecord);
                        newState.reports = prev.reports.map(r => r.id === mapped.id ? mapped : r);
                        if (eventType === 'INSERT') {
                            newState.reports = [mapped, ...newState.reports];
                            if (mapped.status === 'submitted' && currentUser?.role === 'manager') {
                                const sender = prev.users.find(u => u.id === mapped.userId);
                                triggerNotification('تقرير جديد', `وصل تقرير جديد من ${sender?.fullName.split(' ')[0]}`, 'success');
                            }
                        }
                    }
                } 
                localStorage.setItem('daily_tasks_data_cache', JSON.stringify(newState));
                return newState;
            });
        });
        return () => { unsubscribe(); };
    }, [loadData, triggerNotification]);

    const getUserById = useCallback((id: string) => appState.users.find(u => u.id === id), [appState.users]);
    const saveOrUpdateDraft = useCallback(async (draft: Partial<Report>) => { try { await api.saveOrUpdateDraft(draft); refreshData(); } catch (e) { throw e; } }, [refreshData]);
    const addReport = useCallback(async (report: Omit<Report, 'id' | 'sequenceNumber' | 'status'>) => { try { await api.createReport(report); refreshData(); } catch (e) { throw e; } }, [refreshData]);
    const updateReport = useCallback(async (updatedReport: Report) => { try { await api.updateReport(updatedReport); refreshData(); } catch (e) { throw e; } }, [refreshData]);
    const deleteReport = useCallback(async (reportId: string) => { try { await api.deleteReport(reportId); refreshData(); } catch (e) { throw e; } }, [refreshData]);
    const markReportAsViewed = useCallback(async (reportId: string) => { 
        setAppState(prev => ({
            ...prev,
            reports: prev.reports.map(r => r.id === reportId ? { ...r, isViewedByManager: true } : r)
        }));
        await api.markReportAsViewed(reportId); 
    }, []);
    const markAllReportsAsReadForUser = useCallback(async (userId: string) => { 
        setAppState(prev => ({
            ...prev,
            reports: prev.reports.map(r => r.userId === userId ? { ...r, isViewedByManager: true } : r)
        }));
        await api.markAllReportsAsReadForUser(userId); 
    }, []);
    const markCommentAsRead = useCallback(async (reportId: string) => { await api.markCommentAsRead(reportId); refreshData(); }, [refreshData]);
    const addUser = useCallback(async (user: Omit<User, 'id'>) => { await api.createUser(user); refreshData(); }, [refreshData]);
    const updateUser = useCallback(async (updatedUser: User) => { await api.updateUser(updatedUser); refreshData(); }, [refreshData]);
    const deleteUser = useCallback(async (userId: string) => { await api.deleteUser(userId); refreshData(); }, [refreshData]);
    const addAnnouncement = useCallback(async (content: string) => { await api.createAnnouncement(content); refreshData(); }, [refreshData]);
    const updateAnnouncement = useCallback(async (annId: string, content: string) => { await api.updateAnnouncement(annId, content); refreshData(); }, [refreshData]);
    const deleteAnnouncement = useCallback(async (annId: string) => { await api.deleteAnnouncement(annId); refreshData(); }, [refreshData]);
    const markAnnouncementAsRead = useCallback(async (annId: string, uId: string) => { await api.markAnnouncementAsRead(annId, uId); refreshData(); }, [refreshData]);
    const addDirectTask = useCallback(async (task: any) => { await api.createDirectTask(task); refreshData(); }, [refreshData]);
    const updateDirectTaskStatus = useCallback(async (tId: string, s: any, r?: string) => { await api.updateDirectTaskStatus(tId, s, r); refreshData(); }, [refreshData]);
    const markDirectTaskAsRead = useCallback(async (tId: string) => { await api.markDirectTaskAsRead(tId); refreshData(); }, [refreshData]);

    const value = useMemo(() => ({
        ...appState, isDataLoading, isCloud, error, isSyncing, refreshData, notification, clearNotification, getUserById, addReport, updateReport, saveOrUpdateDraft, deleteReport, markReportAsViewed, markAllReportsAsReadForUser,
        markCommentAsRead, addUser, updateUser, deleteUser, addAnnouncement, updateAnnouncement, deleteAnnouncement,
        markAnnouncementAsRead, addDirectTask, updateDirectTaskStatus, markDirectTaskAsRead, unlockAudio, testNotification
    }), [appState, isDataLoading, isCloud, error, isSyncing, refreshData, notification, clearNotification, getUserById, addReport, updateReport, saveOrUpdateDraft, deleteReport, markReportAsViewed, markAllReportsAsReadForUser,
        markCommentAsRead, addUser, updateUser, deleteUser, addAnnouncement, updateAnnouncement, deleteAnnouncement,
        markAnnouncementAsRead, addDirectTask, updateDirectTaskStatus, markDirectTaskAsRead, unlockAudio, testNotification]);

    return <DataContext.Provider value={value}>{children}</DataContext.Provider>;
};

export const useData = (): DataContextType => {
    const context = useContext(DataContext);
    if (!context) throw new Error('useData error');
    return context;
};

import { User, Report, Announcement, DirectTask, Role } from '../types';
import { supabase, isSupabaseConfigured } from './supabaseConfig';

interface AppState {
    users: User[];
    reports: Report[];
    announcements: Announcement[];
    directTasks: DirectTask[];
    isCloud: boolean;
}

const CACHE_KEY = 'daily_tasks_data_cache';
const generateId = () => crypto.randomUUID();

export const mapUser = (row: any): User => ({
    id: row.id,
    fullName: row.full_name,
    badgeNumber: row.badge_number,
    username: row.username,
    password: row.password,
    role: row.role as Role,
    jobTitle: row.job_title,
    unit: row.unit,
    profilePictureUrl: row.profile_picture_url
});

export const mapReport = (row: any): Report => ({
    id: row.id,
    userId: row.user_id,
    sequenceNumber: row.sequence_number,
    date: row.date,
    day: row.day,
    tasks: row.tasks || [],
    accomplished: row.accomplished,
    notAccomplished: row.not_accomplished,
    attachments: row.attachments || [],
    managerComment: row.manager_comment,
    isViewedByManager: row.is_viewed_by_manager,
    isCommentReadByEmployee: row.is_comment_read_by_employee,
    rating: row.rating,
    status: row.status
});

export const mapAnnouncement = (row: any): Announcement => ({
    id: row.id,
    content: row.content,
    date: row.date,
    readBy: row.read_by || []
});

export const mapDirectTask = (row: any): DirectTask => ({
    id: row.id,
    managerId: row.manager_id,
    employeeId: row.employee_id,
    content: row.content,
    sentAt: row.sent_at,
    status: row.status,
    acknowledgedAt: row.acknowledged_at,
    rejectionReason: row.rejection_reason,
    isReadByEmployee: row.is_read_by_employee
});

/**
 * جلب البيانات مع التعامل الذكي مع أخطاء الشبكة
 */
export const fetchInitialData = async (): Promise<AppState> => {
    const cachedData = localStorage.getItem(CACHE_KEY);
    const hasCache = !!cachedData;

    if (!isSupabaseConfigured()) {
        if (hasCache) return JSON.parse(cachedData!);
        throw new Error("تكوين قاعدة البيانات غير مكتمل.");
    }

    try {
        // محاولة الاتصال بالخادم
        const [usersRes, reportsRes, annRes, tasksRes] = await Promise.all([
            supabase.from('users').select('*'),
            supabase.from('reports').select('*').order('date', { ascending: false }),
            supabase.from('announcements').select('*'),
            supabase.from('direct_tasks').select('*')
        ]);

        // التحقق من أخطاء الرد من Supabase
        const errors = [usersRes.error, reportsRes.error, annRes.error, tasksRes.error].filter(Boolean);
        if (errors.length > 0) {
            throw new Error(errors[0]?.message || "خطأ في استجابة الخادم.");
        }

        const freshData: AppState = {
            users: (usersRes.data || []).map(mapUser),
            reports: (reportsRes.data || []).map(mapReport),
            announcements: (annRes.data || []).map(mapAnnouncement),
            directTasks: (tasksRes.data || []).map(mapDirectTask),
            isCloud: true
        };

        // تحديث الكاش للعمليات القادمة
        localStorage.setItem(CACHE_KEY, JSON.stringify(freshData));
        return freshData;
    } catch (error: any) {
        // إذا كان الخطأ هو "Failed to fetch" أو "Network Error"
        const isNetworkError = error.message?.includes('fetch') || error.name === 'TypeError';

        console.warn("API Service Warning:", isNetworkError ? "انقطاع في الشبكة" : error.message);

        if (hasCache) {
            // العودة للبيانات المخزنة دون إزعاج المستخدم
            console.log("استخدام البيانات المخزنة محلياً...");
            return JSON.parse(cachedData!);
        }

        // إذا لم يوجد كاش، نلقي خطأ واضح
        if (isNetworkError) {
            throw new Error("تعذر الاتصال بالخادم. يرجى التأكد من توفر الإنترنت.");
        }
        throw new Error(error.message || "حدث خطأ غير متوقع.");
    }
};

export const subscribeToAllChanges = (onUpdate: (payload: any) => void) => {
    if (!isSupabaseConfigured()) return () => {};

    try {
        const channel = supabase
            .channel('schema-db-changes')
            .on('postgres_changes', { event: '*', schema: 'public', table: 'reports' }, (p) => onUpdate({ table: 'reports', ...p }))
            .on('postgres_changes', { event: '*', schema: 'public', table: 'direct_tasks' }, (p) => onUpdate({ table: 'direct_tasks', ...p }))
            .on('postgres_changes', { event: '*', schema: 'public', table: 'announcements' }, (p) => onUpdate({ table: 'announcements', ...p }))
            .on('postgres_changes', { event: '*', schema: 'public', table: 'users' }, (p) => onUpdate({ table: 'users', ...p }))
            .subscribe();

        return () => { supabase.removeChannel(channel); };
    } catch (e) {
        console.warn("Realtime connection skipped due to network issues.");
        return () => {};
    }
};

export const createReport = async (report: Omit<Report, 'id' | 'sequenceNumber' | 'status'>): Promise<Report> => {
    const { data: maxSeqData } = await supabase
        .from('reports')
        .select('sequence_number')
        .eq('user_id', report.userId)
        .eq('status', 'submitted')
        .order('sequence_number', { ascending: false })
        .limit(1);

    const maxSeq = maxSeqData && maxSeqData.length > 0 ? maxSeqData[0].sequence_number : 0;
    const newId = generateId();
    const dbReport = {
        id: newId, 
        user_id: report.userId, 
        sequence_number: maxSeq + 1, 
        date: report.date, 
        day: report.day,
        tasks: report.tasks, 
        accomplished: report.accomplished, 
        not_accomplished: report.notAccomplished,
        attachments: report.attachments, 
        status: 'submitted', 
        is_viewed_by_manager: false, 
        is_comment_read_by_employee: false
    };
    const { error } = await supabase.from('reports').insert(dbReport);
    if (error) throw error;
    return { ...report, id: newId, status: 'submitted', sequenceNumber: maxSeq + 1 } as Report;
};

export const saveOrUpdateDraft = async (draft: Partial<Report>): Promise<Report> => {
    const dbPayload = {
        user_id: draft.userId, date: draft.date, day: draft.day, tasks: draft.tasks || [],
        accomplished: draft.accomplished || '', not_accomplished: draft.notAccomplished || '',
        attachments: draft.attachments || [], status: 'draft', sequence_number: null
    };

    if (draft.id && !draft.id.startsWith('temp-')) {
        const { error } = await supabase.from('reports').update(dbPayload).eq('id', draft.id);
        if (error) throw error;
        return { ...draft, status: 'draft' } as Report;
    } else {
        const newId = generateId();
        const { error } = await supabase.from('reports').insert({ id: newId, ...dbPayload });
        if (error) throw error;
        return { ...draft, id: newId, status: 'draft' } as Report;
    }
};

export const updateReport = async (updatedReport: Report): Promise<Report> => {
    const { error } = await supabase.from('reports').update({
        tasks: updatedReport.tasks, accomplished: updatedReport.accomplished,
        not_accomplished: updatedReport.notAccomplished, attachments: updatedReport.attachments,
        manager_comment: updatedReport.managerComment, rating: updatedReport.rating,
        status: updatedReport.status, is_viewed_by_manager: updatedReport.isViewedByManager,
        is_comment_read_by_employee: updatedReport.isCommentReadByEmployee
    }).eq('id', updatedReport.id);
    if (error) throw error;
    return updatedReport;
};

export const deleteReport = async (reportId: string): Promise<void> => {
    await supabase.from('reports').delete().eq('id', reportId);
};

export const markReportAsViewed = async (reportId: string): Promise<void> => {
    await supabase.from('reports').update({ is_viewed_by_manager: true }).eq('id', reportId);
};

export const markAllReportsAsReadForUser = async (userId: string): Promise<void> => {
    await supabase.from('reports').update({ is_viewed_by_manager: true }).eq('user_id', userId).eq('status', 'submitted');
};

export const markCommentAsRead = async (reportId: string): Promise<void> => {
    await supabase.from('reports').update({ is_comment_read_by_employee: true }).eq('id', reportId);
};

export const createDirectTask = async (task: Omit<DirectTask, 'id' | 'sentAt' | 'status' | 'isReadByEmployee'>): Promise<DirectTask> => {
    const newId = generateId();
    const dbTask = { id: newId, manager_id: task.managerId, employee_id: task.employeeId, content: task.content, sent_at: new Date().toISOString(), status: 'pending', is_read_by_employee: false };
    const { error } = await supabase.from('direct_tasks').insert(dbTask);
    if (error) throw error;
    return { ...task, id: newId, sentAt: dbTask.sent_at, status: 'pending', isReadByEmployee: false };
};

export const updateDirectTaskStatus = async (taskId: string, status: 'acknowledged' | 'rejected', rejectionReason?: string): Promise<void> => {
    const updates: any = { status };
    if (rejectionReason) updates.rejection_reason = rejectionReason;
    if (status === 'acknowledged') updates.acknowledged_at = new Date().toISOString();
    await supabase.from('direct_tasks').update(updates).eq('id', taskId);
};

export const markDirectTaskAsRead = async (taskId: string): Promise<void> => {
    await supabase.from('direct_tasks').update({ is_read_by_employee: true }).eq('id', taskId);
};

export const createUser = async (user: Omit<User, 'id'>): Promise<User> => {
    const newId = generateId();
    await supabase.from('users').insert({ id: newId, full_name: user.fullName, badge_number: user.badgeNumber, username: user.username, password: user.password, role: user.role, job_title: user.jobTitle, unit: user.unit, profile_picture_url: user.profilePictureUrl });
    return { ...user, id: newId };
};

export const updateUser = async (updatedUser: User): Promise<User> => {
    await supabase.from('users').update({ full_name: updatedUser.fullName, badge_number: updatedUser.badgeNumber, username: updatedUser.username, password: updatedUser.password, role: updatedUser.role, job_title: updatedUser.jobTitle, unit: updatedUser.unit, profile_picture_url: updatedUser.profilePictureUrl }).eq('id', updatedUser.id);
    return updatedUser;
};

export const deleteUser = async (userId: string): Promise<void> => {
    await supabase.from('reports').delete().eq('user_id', userId);
    await supabase.from('users').delete().eq('id', userId);
};

export const createAnnouncement = async (content: string): Promise<Announcement> => {
    const newId = generateId();
    const { error } = await supabase.from('announcements').insert({ id: newId, content, date: new Date().toISOString(), read_by: [] });
    if (error) throw error;
    return { id: newId, content, date: new Date().toISOString(), readBy: [] };
};

export const updateAnnouncement = async (announcementId: string, content: string): Promise<Announcement> => {
    await supabase.from('announcements').update({ content }).eq('id', announcementId);
    return { id: announcementId, content } as Announcement;
};

export const deleteAnnouncement = async (announcementId: string): Promise<void> => {
    await supabase.from('announcements').delete().eq('id', announcementId);
};

export const markAnnouncementAsRead = async (announcementId: string, userId: string): Promise<void> => {
    const { data } = await supabase.from('announcements').select('read_by').eq('id', announcementId).single();
    if (data) {
        const currentReadBy = data.read_by || [];
        if (!currentReadBy.some((r: any) => r.userId === userId)) {
            const updatedReadBy = [...currentReadBy, { userId, readAt: new Date().toISOString() }];
            await supabase.from('announcements').update({ read_by: updatedReadBy }).eq('id', announcementId);
        }
    }
};

import React, { createContext, useState, useContext, ReactNode, useMemo, useCallback, useEffect, useRef } from 'react';
import { User, Report, Announcement, DirectTask } from '../types';
import * as api from '../services/apiService';

interface AppState {
    users: User[];
    reports: Report[];
    announcements: Announcement[];
    directTasks: DirectTask[];
}

interface DataContextType extends AppState {
    isDataLoading: boolean;
    isCloud: boolean;
    error: string | null;
    isSyncing: boolean;
    refreshData: () => Promise<void>;
    notification: { message: string, type: 'info' | 'success', id: number } | null;
    clearNotification: () => void;
    getUserById: (id: string) => User | undefined;
    addReport: (report: Omit<Report, 'id' | 'sequenceNumber' | 'status'>) => Promise<void>;
    updateReport: (updatedReport: Report) => Promise<void>;
    saveOrUpdateDraft: (draft: Partial<Report>) => Promise<void>;
    deleteReport: (reportId: string) => Promise<void>;
    markReportAsViewed: (reportId: string) => Promise<void>;
    markAllReportsAsReadForUser: (userId: string) => Promise<void>;
    markCommentAsRead: (reportId: string) => Promise<void>;
    addUser: (user: Omit<User, 'id'>) => Promise<void>;
    updateUser: (user: User) => Promise<void>;
    deleteUser: (userId: string) => Promise<void>;
    addAnnouncement: (content: string) => Promise<void>;
    updateAnnouncement: (announcementId: string, content: string) => Promise<void>;
    deleteAnnouncement: (announcementId: string) => Promise<void>;
    markAnnouncementAsRead: (announcementId: string, userId: string) => Promise<void>;
    addDirectTask: (task: Omit<DirectTask, 'id' | 'sentAt' | 'status' | 'isReadByEmployee'>) => Promise<void>;
    updateDirectTaskStatus: (taskId: string, status: 'acknowledged' | 'rejected', rejectionReason?: string) => Promise<void>;
    markDirectTaskAsRead: (taskId: string) => Promise<void>;
    unlockAudio: () => void;
