    updateDirectTaskStatus: (taskId: string, status: 'acknowledged' | 'rejected', rejectionReason?: string) => Promise<void>;
    markDirectTaskAsRead: (taskId: string) => Promise<void>;
    unlockAudio: () => void;
    testNotification: () => void;
}

const DataContext = createContext<DataContextType | undefined>(undefined);

export const DataProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
    const [appState, setAppState] = useState<AppState>({
        users: [],
        reports: [],
        announcements: [],
        directTasks: []
    });

    const [isDataLoading, setIsDataLoading] = useState(true);
    const [error, setError] = useState<string | null>(null);
    const [notification, setNotification] = useState<{ message: string, type: 'info' | 'success', id: number } | null>(null);

    const audioRef = useRef<HTMLAudioElement | null>(null);

    useEffect(() => {
        audioRef.current = new Audio('https://assets.mixkit.co/active_storage/sfx/2358/2358-preview.mp3');
        audioRef.current.load();
    }, []);

    const unlockAudio = useCallback(() => {
        if (audioRef.current) {
            audioRef.current.play().then(() => {
                audioRef.current?.pause();
                if (audioRef.current) audioRef.current.currentTime = 0;
            }).catch(() => {});
        }
    }, []);

    const playNotificationSound = useCallback(() => {
        if (audioRef.current) {
            audioRef.current.currentTime = 0;
            audioRef.current.volume = 0.6;
            audioRef.current.play().catch(() => {});
        }
    }, []);

    const triggerNotification = useCallback((title: string, body: string, type: 'info' | 'success' = 'info') => {
        setNotification({ message: body, type, id: Date.now() });
        playNotificationSound();
    }, [playNotificationSound]);

    const clearNotification = useCallback(() => setNotification(null), []);

    const loadData = useCallback(async () => {
        setIsDataLoading(true);
        try {
            const data = await api.fetchInitialData();
            setAppState(data);
            setError(null);
        } catch (err: any) {
            setError(err.message || "فشل تحميل البيانات.");
        } finally {
            setIsDataLoading(false);
        }
    }, []);

    const refreshData = useCallback(async () => {
        try {
            const data = await api.fetchInitialData();
            setAppState(data);
        } catch (e) {}
    }, []);

    useEffect(() => {
        loadData();
        const unsubscribe = api.subscribeToAllChanges(() => {
            refreshData();
        });
        return () => { unsubscribe(); };
    }, [loadData, refreshData]);

    const addReport = useCallback(async (report: Omit<Report, 'id' | 'sequenceNumber' | 'status'>) => {
        await api.createReport(report);
        await refreshData();
    }, [refreshData]);

    const updateReport = useCallback(async (updatedReport: Report) => {
        await api.updateReport(updatedReport);
        await refreshData();
    }, [refreshData]);

    const saveOrUpdateDraft = useCallback(async (draft: Partial<Report>) => {
        await api.saveOrUpdateDraft(draft);
        await refreshData();
    }, [refreshData]);

    const deleteReport = useCallback(async (reportId: string) => {
        await api.deleteReport(reportId);
        await refreshData();
    }, [refreshData]);

    const markReportAsViewed = useCallback(async (reportId: string) => {
        await api.markReportAsViewed(reportId);
        await refreshData();
    }, [refreshData]);

    const markAllReportsAsReadForUser = useCallback(async (userId: string) => {
        await api.markAllReportsAsReadForUser(userId);
        await refreshData();
    }, [refreshData]);

    const markCommentAsRead = useCallback(async (reportId: string) => {
        await api.markCommentAsRead(reportId);
        await refreshData();
    }, [refreshData]);

    const addUser = useCallback(async (user: Omit<User, 'id'>) => {
        await api.createUser(user);
        await refreshData();
    }, [refreshData]);

    const updateUser = useCallback(async (updatedUser: User) => {
        await api.updateUser(updatedUser);
        await refreshData();
    }, [refreshData]);

    const deleteUser = useCallback(async (userId: string) => {
        await api.deleteUser(userId);
        await refreshData();
    }, [refreshData]);

    const addAnnouncement = useCallback(async (content: string) => {
        await api.createAnnouncement(content);
        await refreshData();
    }, [refreshData]);

    const updateAnnouncement = useCallback(async (annId: string, content: string) => {
        await api.updateAnnouncement(annId, content);
        await refreshData();
    }, [refreshData]);

    const deleteAnnouncement = useCallback(async (annId: string) => {
        await api.deleteAnnouncement(annId);
        await refreshData();
    }, [refreshData]);

    const markAnnouncementAsRead = useCallback(async (annId: string, uId: string) => {
        await api.markAnnouncementAsRead(annId, uId);
        await refreshData();
    }, [refreshData]);

    const addDirectTask = useCallback(async (task: any) => {
        await api.createDirectTask(task);
        await refreshData();
    }, [refreshData]);

    const updateDirectTaskStatus = useCallback(async (tId: string, s: any, r?: string) => {
        await api.updateDirectTaskStatus(tId, s, r);
        await refreshData();
    }, [refreshData]);

    const markDirectTaskAsRead = useCallback(async (tId: string) => {
        await api.markDirectTaskAsRead(tId);
        await refreshData();
    }, [refreshData]);

    const testNotification = useCallback(() => {
        triggerNotification("تجربة النظام", "أهلاً بك، نظام التنبيهات يعمل بنجاح.", "success");
    }, [triggerNotification]);

    const getUserById = useCallback((id: string) => appState.users.find(u => u.id === id), [appState.users]);

    const value = useMemo(() => ({
        ...appState, isDataLoading, error, refreshData, notification, clearNotification, getUserById, addReport, updateReport, saveOrUpdateDraft, deleteReport, markReportAsViewed, markAllReportsAsReadForUser,
        markCommentAsRead, addUser, updateUser, deleteUser, addAnnouncement, updateAnnouncement, deleteAnnouncement,
        markAnnouncementAsRead, addDirectTask, updateDirectTaskStatus, markDirectTaskAsRead, unlockAudio, testNotification, isCloud: true, isSyncing: false
    }), [appState, isDataLoading, error, refreshData, notification, clearNotification, getUserById, addReport, updateReport, saveOrUpdateDraft, deleteReport, markReportAsViewed, markAllReportsAsReadForUser,
        markCommentAsRead, addUser, updateUser, deleteUser, addAnnouncement, updateAnnouncement, deleteAnnouncement,
        markAnnouncementAsRead, addDirectTask, updateDirectTaskStatus, markDirectTaskAsRead, unlockAudio, testNotification]);

    return <DataContext.Provider value={value}>{children}</DataContext.Provider>;
};

export const useData = (): DataContextType => {
    const context = useContext(DataContext);
    if (!context) throw new Error('useData error');
    return context;
};

import React from 'react';
import { AuthProvider, useAuth } from './context/AuthContext';
import { DataProvider, useData } from './context/DataContext';
import Login from './components/Login';
import EmployeeDashboard from './components/EmployeeDashboard';
import ManagerDashboard from './components/ManagerDashboard';
import { ThemeProvider } from './context/ThemeContext';
import ExclamationCircleIcon from './components/icons/ExclamationCircleIcon';
import InstallPWA from './components/InstallPWA';

const AppContent: React.FC = () => {
    const { currentUser, loading: authLoading } = useAuth();
    const { isDataLoading, error } = useData();

    if (error) {
        return (
            <div className="flex flex-col items-center justify-center min-h-screen bg-gray-50 dark:bg-gray-900 p-4 text-center">
                 <div className="bg-white dark:bg-gray-800 p-8 rounded-lg shadow-xl max-w-md w-full border border-red-200 dark:border-red-900">
                    <ExclamationCircleIcon className="w-16 h-16 text-red-500 mx-auto mb-4" />
                    <h2 className="text-xl font-bold text-gray-800 dark:text-gray-100 mb-2">خطأ في الاتصال</h2>
                    <p className="text-gray-600 dark:text-gray-300 mb-6">{error}</p>

                    <button 
                        onClick={() => window.location.reload()}
                        className="w-full px-4 py-2 bg-brand-light text-white rounded hover:bg-brand-dark transition-colors"
                    >
                        إعادة المحاولة
                    </button>
                 </div>
            </div>
        );
    }

    if (authLoading || isDataLoading) {
        return (
            <div className="flex items-center justify-center min-h-screen bg-gray-100 dark:bg-gray-900">
                <div className="flex flex-col items-center">
                    <div className="w-12 h-12 border-4 border-brand-light border-t-transparent rounded-full animate-spin mb-4"></div>
                    <div className="text-xl font-semibold text-gray-700 dark:text-gray-300">جارِ التحميل...</div>
                </div>
            </div>
        );
    }

    return (
        <div className="min-h-screen bg-gray-50 dark:bg-gray-900">
            {!currentUser ? <Login /> : (currentUser.role === 'employee' ? <EmployeeDashboard /> : <ManagerDashboard />)}
            <InstallPWA />
        </div>
    );
};

const App: React.FC = () => {
    return (
        <ThemeProvider>
            <DataProvider>
                <AuthProvider>
                    <AppContent />
                </AuthProvider>
            </DataProvider>
        </ThemeProvider>
    );
};

export default App;

